            new Shipment { Id = 5, TrackingNumber = "SHP-1005", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, ShippedDate = now.AddDays(-5), EstimatedDelivery = now.AddDays(1), RecipientName = "Eve Martinez", CarrierName = "QuickShip", WeightKg = 15.7 },
