@code {
    private List<Shipment>? shipments;
    private bool isLoading;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;
    private string sortColumn = "TrackingNumber";
    private bool sortAscending = true;
    private int? editingShipmentId;
    private ShipmentStatus newStatus;

    protected override async Task OnInitializedAsync()
    {
        await RefreshData();
    }

    private async Task RefreshData()
    {
        isLoading = true;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        finally
        {
            isLoading = false;
        }
    }

    private IEnumerable<Shipment> FilteredShipments
    {
        get
        {
            if (shipments is null) return [];

            var result = shipments.AsEnumerable();

            if (!string.IsNullOrWhiteSpace(searchTerm))
            {
                var term = searchTerm.Trim();
                result = result.Where(s =>
                    s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.RecipientName.Contains(term, StringComparison.OrdinalIgnoreCase));
            }

            if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
            {
                result = result.Where(s => s.Status == status);
            }

            result = sortColumn switch
            {
                "TrackingNumber" => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber),
                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
                "EstimatedDelivery" => sortAscending ? result.OrderBy(s => s.EstimatedDelivery) : result.OrderByDescending(s => s.EstimatedDelivery),
                _ => result
            };

            return result;
        }
    }

    private void SetSort(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column)
    {
        if (sortColumn != column) return "";
        return sortAscending ? "▲" : "▼";
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        statusFilter = string.Empty;
    }

    private void StartEdit(Shipment shipment)
    {
        editingShipmentId = shipment.Id;
        newStatus = shipment.Status;
    }

    private void CancelEdit()
    {
        editingShipmentId = null;
    }

    private async Task SaveStatus(int id)
    {
        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
        editingShipmentId = null;
        await RefreshData();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-primary",
        _ => "bg-secondary"
    };
}
```

