namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string CarrierName { get; set; } = string.Empty;
    public double WeightKg { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed,
    Returned
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment?> GetShipmentByIdAsync(int id);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await httpClient.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        var response = await httpClient.GetAsync($"api/shipments/{id}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", status);
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly List<Shipment> Shipments = GenerateSeedData();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(Shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = Shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = status;
            if (status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
        }
        return Task.CompletedTask;
    }

    private static List<Shipment> GenerateSeedData()
    {
        var now = DateTime.UtcNow;
        return
        [
            new Shipment { Id = 1, TrackingNumber = "SHP-1001", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, ShippedDate = now.AddDays(-3), EstimatedDelivery = now.AddDays(2), RecipientName = "Alice Johnson", CarrierName = "FastFreight", WeightKg = 12.5 },
            new Shipment { Id = 2, TrackingNumber = "SHP-1002", Origin = "Chicago, IL", Destination = "Houston, TX", Status = ShipmentStatus.Delivered, ShippedDate = now.AddDays(-7), EstimatedDelivery = now.AddDays(-2), ActualDelivery = now.AddDays(-2), RecipientName = "Bob Smith", CarrierName = "QuickShip", WeightKg = 5.0 },
            new Shipment { Id = 3, TrackingNumber = "SHP-1003", Origin = "Seattle, WA", Destination = "Miami, FL", Status = ShipmentStatus.Pending, ShippedDate = now, EstimatedDelivery = now.AddDays(5), RecipientName = "Carol Davis", CarrierName = "GlobalLogistics", WeightKg = 25.0 },
            new Shipment { Id = 4, TrackingNumber = "SHP-1004", Origin = "Denver, CO", Destination = "Boston, MA", Status = ShipmentStatus.OutForDelivery, ShippedDate = now.AddDays(-4), EstimatedDelivery = now, RecipientName = "Dan Wilson", CarrierName = "FastFreight", WeightKg = 8.3 },
            new Shipment { Id = 5, TrackingNumber = "SHP-1005", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, ShippedDate = now.AddDays(-5), EstimatedDelivery = now.AddDays(1), RecipientName = "Eve Martinez", CarrierName = "QuickShip", WeightKg = 15.7 },
            new Shipment { Id = 6, TrackingNumber = "SHP-1006", Origin = "Atlanta, GA", Destination = "Detroit, MI", Status = ShipmentStatus.PickedUp, ShippedDate = now.AddDays(-1), EstimatedDelivery = now.AddDays(3), RecipientName = "Frank Lee", CarrierName = "GlobalLogistics", WeightKg = 3.2 },
            new Shipment { Id = 7, TrackingNumber = "SHP-1007", Origin = "Portland, OR", Destination = "Nashville, TN", Status = ShipmentStatus.InTransit, ShippedDate = now.AddDays(-2), EstimatedDelivery = now.AddDays(3), RecipientName = "Grace Kim", CarrierName = "FastFreight", WeightKg = 20.0 },
            new Shipment { Id = 8, TrackingNumber = "SHP-1008", Origin = "Dallas, TX", Destination = "Philadelphia, PA", Status = ShipmentStatus.Returned, ShippedDate = now.AddDays(-10), EstimatedDelivery = now.AddDays(-5), RecipientName = "Hank Brown", CarrierName = "QuickShip", WeightKg = 7.1 },
        ];
