<PageTitle>Track Shipment</PageTitle>

<div class="container">
    <h1>Track Your Shipment</h1>
    <p>Enter your tracking number below to check your shipment status.</p>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="e.g. SHP-1001"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isLoading">
                    @if (isLoading)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Search
                </button>
            </div>
        </div>
    </div>

    @if (searched && shipment is null && !isLoading)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>". Please check the number and try again.
        </div>
    }

    @if (shipment is not null)
    {
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>@shipment.TrackingNumber</strong>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
