public class ServerShipmentService : IShipmentService
{
    private static readonly List<Shipment> Shipments = GenerateSeedData();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(Shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = Shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = status;
            if (status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
