+@page "/shipments"
+@using Microsoft.AspNetCore.Authorization
+@using ShipmentTracker.Client.Models
+@using ShipmentTracker.Client.Services
+@attribute [Authorize]
+@inject IShipmentService ShipmentService
+
+<PageTitle>Dispatch Dashboard</PageTitle>
+
+<div class="container-fluid">
+    <h1>Dispatch Dashboard</h1>
+    <p>Manage and monitor all shipments.</p>
+
+    <div class="row mb-3">
+        <div class="col-md-4">
+            <input type="text" class="form-control" placeholder="Search by tracking #, destination, or recipient..."
+                   @bind="searchTerm" @bind:event="oninput" />
+        </div>
+        <div class="col-md-3">
+            <select class="form-select" @bind="statusFilter">
+                <option value="">All Statuses</option>
+                @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                {
+                    <option value="@status">@status</option>
+                }
+            </select>
+        </div>
+        <div class="col-md-2">
+            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
+        </div>
+        <div class="col-md-3 text-end">
+            <button class="btn btn-primary" @onclick="RefreshData" disabled="@isLoading">
+                @if (isLoading)
+                {
+                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+                }
+                Refresh
+            </button>
+        </div>
+    </div>
+
+    @if (isLoading && shipments is null)
+    {
+        <div class="text-center py-5">
+            <div class="spinner-border text-primary" role="status">
+                <span class="visually-hidden">Loading...</span>
+            </div>
+            <p class="mt-2">Loading shipments...</p>
+        </div>
+    }
+    else if (shipments is not null)
+    {
+        <div class="table-responsive">
+            <table class="table table-striped table-hover">
+                <thead class="table-dark">
+                    <tr>
+                        <th @onclick='() => SetSort("TrackingNumber")' style="cursor: pointer">
+                            Tracking # @SortIndicator("TrackingNumber")
+                        </th>
+                        <th @onclick='() => SetSort("Destination")' style="cursor: pointer">
+                            Destination @SortIndicator("Destination")
+                        </th>
+                        <th @onclick='() => SetSort("Status")' style="cursor: pointer">
+                            Status @SortIndicator("Status")
+                        </th>
+                        <th @onclick='() => SetSort("EstimatedDelivery")' style="cursor: pointer">
+                            Est. Delivery @SortIndicator("EstimatedDelivery")
+                        </th>
+                        <th>Recipient</th>
+                        <th>Carrier</th>
+                        <th>Weight (kg)</th>
+                        <th>Actions</th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var s in FilteredShipments)
+                    {
+                        <tr>
+                            <td><strong>@s.TrackingNumber</strong></td>
+                            <td>@s.Destination</td>
+                            <td>
+                                @if (editingShipmentId == s.Id)
+                                {
+                                    <select class="form-select form-select-sm" @bind="newStatus">
+                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                        {
+                                            <option value="@status">@status</option>
+                                        }
+                                    </select>
+                                }
+                                else
+                                {
+                                    <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
+                                }
+                            </td>
+                            <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
+                            <td>@s.RecipientName</td>
+                            <td>@s.CarrierName</td>
+                            <td>@s.WeightKg.ToString("F1")</td>
+                            <td>
+                                @if (editingShipmentId == s.Id)
+                                {
+                                    <button class="btn btn-sm btn-success me-1" @onclick="() => SaveStatus(s.Id)">Save</button>
+                                    <button class="btn btn-sm btn-secondary" @onclick="CancelEdit">Cancel</button>
+                                }
+                                else
+                                {
+                                    <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(s)">Update</button>
+                                }
+                            </td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+
+        <div class="text-muted mt-2">
+            Showing @FilteredShipments.Count() of @shipments.Count shipments
+        </div>
+    }
+</div>
+
+@code {
+    private List<Shipment>? shipments;
+    private bool isLoading;
+    private string searchTerm = string.Empty;
+    private string statusFilter = string.Empty;
+    private string sortColumn = "TrackingNumber";
+    private bool sortAscending = true;
+    private int? editingShipmentId;
+    private ShipmentStatus newStatus;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await RefreshData();
+    }
+
+    private async Task RefreshData()
+    {
+        isLoading = true;
+        try
+        {
+            shipments = await ShipmentService.GetAllShipmentsAsync();
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private IEnumerable<Shipment> FilteredShipments
+    {
+        get
+        {
+            if (shipments is null) return [];
+
+            var result = shipments.AsEnumerable();
+
+            if (!string.IsNullOrWhiteSpace(searchTerm))
+            {
+                var term = searchTerm.Trim();
+                result = result.Where(s =>
+                    s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                    s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                    s.RecipientName.Contains(term, StringComparison.OrdinalIgnoreCase));
+            }
+
+            if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
+            {
+                result = result.Where(s => s.Status == status);
+            }
+
+            result = sortColumn switch
+            {
+                "TrackingNumber" => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber),
+                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
+                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
+                "EstimatedDelivery" => sortAscending ? result.OrderBy(s => s.EstimatedDelivery) : result.OrderByDescending(s => s.EstimatedDelivery),
+                _ => result
+            };
+
+            return result;
+        }
+    }
+
+    private void SetSort(string column)
+    {
+        if (sortColumn == column)
+            sortAscending = !sortAscending;
+        else
+        {
+            sortColumn = column;
+            sortAscending = true;
+        }
+    }
+
+    private string SortIndicator(string column)
+    {
+        if (sortColumn != column) return "";
+        return sortAscending ? "▲" : "▼";
+    }
+
+    private void ClearFilters()
+    {
+        searchTerm = string.Empty;
+        statusFilter = string.Empty;
+    }
+
+    private void StartEdit(Shipment shipment)
+    {
+        editingShipmentId = shipment.Id;
+        newStatus = shipment.Status;
+    }
+
+    private void CancelEdit()
+    {
+        editingShipmentId = null;
+    }
+
+    private async Task SaveStatus(int id)
+    {
+        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
+        editingShipmentId = null;
+        await RefreshData();
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.Delayed => "bg-warning text-dark",
+        ShipmentStatus.Returned => "bg-danger",
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-primary",
+        _ => "bg-secondary"
+    };
+}
+

